lifecycle_commands.create:
zx <<'EOF'

      cd('/tmp');
      await $`curl -OL https://awscli.amazonaws.com/awscli-exe-linux-x86_64.zip`;
      await $`unzip awscli-exe-linux-x86_64.zip`
	await $`./aws/install -i /home/hallcor/.local -b /home/hallcor/.local/bin`
      const location = await which('aws');
      const version = await $`aws --version`;
      echo`{
        name: 'aws',
        location: $${location},
        version: $${version},
      }`;

EOF

lifecycle_commands.delete:
zx <<'EOF'

      const location = await which('aws');
      await $`rm -rf $${location}`;
      await $`rm -rf /home/hallcor/.local`;

EOF

lifecycle_commands.read:
zx <<'EOF'

      try {
        const location = await which('aws');
        const version = await $`aws --version`;
        echo`{
          location: $${location},
          version: $${version},
          name: 'aws',
        }`
      } catch {}

EOF

lifecycle_commands.update:
zx <<'EOF'

      cd('/tmp');
      await $`curl -OL https://awscli.amazonaws.com/awscli-exe-linux-x86_64.zip`;
      await $`./aws/install -i /home/hallcor/.local -b /home/hallcor/.local/bin --update`
      const location = await which('aws');
      const version = await $`aws --version`;
      echo`{
        name: 'aws',
        location: $${location},
        version: $${version},
      }`;

EOF
